import React, { useState, useEffect } from "react";
//import { useAuth } from './context/AuthContext'; // ajuste o caminho conforme sua estrutura

export default function FormTratamento({
  denteSelecionado,
  regiaoSelecionada,
  onAdicionarTratamento,
}) {
  const { user } = useAuth();
  const [form, setForm] = useState({
    tratamento: "",
    regiao: regiaoSelecionada || "",
    dente: denteSelecionado || "",
    profissional: user?.nome || "",
  });

  // Atualiza campo ao selecionar dente/região
  useEffect(() => {
    setForm(f => ({
      ...f,
      dente: denteSelecionado || "",
      regiao: regiaoSelecionada || "",
      profissional: user?.nome || "",
    }));
  }, [denteSelecionado, regiaoSelecionada, user]);

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.tratamento || !form.dente || !form.regiao) return;
    onAdicionarTratamento({
      ...form,
      status: "aberto",
      criadoEm: new Date().toISOString(),
      id: Math.random().toString(36).slice(2),
    });
    setForm(f => ({
      ...f,
      tratamento: "",
      regiao: "",
      dente: "",
      // profissional mantem user logado
    }));
  }

  return (
    <form onSubmit={handleSubmit} className="bg-gray-50 p-4 rounded shadow mb-4">
      <div className="flex flex-wrap gap-4 mb-2 items-end">
        <div>
          <label className="text-xs text-gray-500">Tratamento*</label>
          <input
            name="tratamento"
            className="block w-48 border rounded px-2 py-1"
            value={form.tratamento}
            onChange={handleChange}
            required
            autoFocus
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Região*</label>
          <select
            name="regiao"
            className="block w-28 border rounded px-2 py-1"
            value={form.regiao}
            onChange={handleChange}
            required
          >
            <option value="">Selecione</option>
            <option value="Coroa">Coroa</option>
            <option value="Vestibular">Vestibular</option>
            <option value="Palatina">Palatina</option>
            <option value="Lingual">Lingual</option>
            <option value="Mesial">Mesial</option>
            <option value="Distal">Distal</option>
            {/* adicione outras regiões se quiser */}
          </select>
        </div>
        <div>
          <label className="text-xs text-gray-500">Dente*</label>
          <input
            name="dente"
            className="block w-16 border rounded px-2 py-1"
            value={form.dente}
            onChange={handleChange}
            required
            readOnly
          />
        </div>
        <div>
          <label className="text-xs text-gray-500">Profissional</label>
          <input
            name="profissional"
            className="block w-44 border rounded px-2 py-1 bg-gray-100"
            value={form.profissional}
            readOnly
            disabled
          />
        </div>
        <button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded font-semibold"
        >
          Adicionar
        </button>
      </div>
    </form>
  );
}
